// ── Dimensional Mastery ─────────────────────────────────────────────

/**
 * What each completed dimension permanently grants.
 *
 * These are not choices — they are physics.
 * Complete dimension N → permanently gain mastery N.
 * The observer formalizes the skill tree, shaped by what it survived.
 */
export interface DimensionalMastery {
  /** Dimension index that was mastered */
  readonly dimension: GnosticDimensionIndex;
  /** Human-readable name */
  readonly name: string;
  /** What this mastery grants */
  readonly description: string;
  /** Permanent modifier to God Formula parameters */
  readonly modifier: GodFormulaModifier;
  /** Max HEX increase (health scaling) */
  readonly energyCapacityBonus: number;
  /** Fast travel compression bonus (additive, stacks) */
  readonly fastTravelBonus: number;
  /** Stagnation grace period extension (picolorenzos) */
  readonly stagnationGrace: number;
}

