// ── Mastery Calculation ─────────────────────────────────────────────

/**
 * Calculate the total mastery modifier for a observer based on
 * their highest completed dimension.
 *
 * All masteries up to and including highestDimension stack.
 * R bonus and w bonus stack additively.
 * v multiplier and drain resistance stack multiplicatively.
 */
export function calculateMasteryModifier(
  highestDimension: number
): GodFormulaModifier {
  let rBonus = 0;
  let vMultiplier = 1;
  let wBonus = 0;
  let moveCostReduction = 0;
  let learningBonus = 0;
  let drainResistance = 1;

  for (let d = 0; d <= Math.min(highestDimension, 9); d++) {
    const mastery = DIMENSIONAL_MASTERIES.get(d as GnosticDimensionIndex);
    if (!mastery) continue;
    rBonus += mastery.modifier.rBonus;
    vMultiplier *= mastery.modifier.vMultiplier;
    wBonus += mastery.modifier.wBonus;
    moveCostReduction = Math.min(0.9, moveCostReduction + mastery.modifier.moveCostReduction);
    learningBonus += mastery.modifier.learningBonus;
    drainResistance *= mastery.modifier.drainResistance;
  }

  return { rBonus, vMultiplier, wBonus, moveCostReduction, learningBonus, drainResistance };
}

/**
 * Calculate the max HEX (health) for a observer based on mastery.
 *
 * Max HEX = BASE + Σ(β₁(d) × 10) for all mastered dimensions d.
 *
 * Health formalizes the gnostic number at each dimension, scaled by 10.
 * The math determines your health pool. No arbitrary numbers.
 *
 * Dim 0 mastery: 100 + 0  = 100  (you're still nothing)
 * Dim 3 mastery: 100 + 60 = 160  (the plane comforts you)
 * Dim 5 mastery: 100 + 170 = 270 (time gives perspective)
 * Dim 9 mastery: 100 + 1120 = 1220 (fullness)
 *
 * The gnostic numbers: 0, 1, 2, 3, 5, 6, 9, 10, 21, 55
 * Sum = 112. × 10 = 1120. + 100 base = 1220 max HEX.
 */
export function calculateEnergyCapacity(highestDimension: number): number {
  const BASE_HEX = 100;
  const HEALTH_PER_BETA = 10;
  let bonus = 0;

  for (let d = 0; d <= Math.min(highestDimension, 9); d++) {
    const dimDef = GNOSTIC_DIMENSIONS.find(
      (dim) => dim.index === d
    );
    if (dimDef) bonus += dimDef.beta1 * HEALTH_PER_BETA;
  }

  return BASE_HEX + bonus;
}

/**
 * Calculate the total stagnation grace period for a observer.
 *
 * Base: 3 picolorenzos
 * Each completed dimension adds grace.
 * Pleroma master: 3 + 0+1+1+2+2+3+4+5+8+13 = 42 picolorenzos
 * (42 — the answer to everything. Not an accident.)
 */
export function calculateStagnationGrace(highestDimension: number): number {
  const BASE_GRACE = 3;
  let bonus = 0;

  for (let d = 0; d <= Math.min(highestDimension, 9); d++) {
    const mastery = DIMENSIONAL_MASTERIES.get(d as GnosticDimensionIndex);
    if (mastery) bonus += mastery.stagnationGrace;
  }

  return BASE_GRACE + bonus;
}

/**
 * Calculate the time (in ticks) an unlogged / inactive player can persist in the void
 * before being vented to the universe.
 * 
 * Scales identically to the thermodynamic time dilation parameter (β₁).
 * Higher dimensions have vastly more structural rigidity, so they evaporate much slower.
 */
export function calculateEvaporationTime(dimension: DimensionIndex): number {
  const BASE_KEEPALIVE_TICKS = 100;
  const beta1 = Math.abs(DIMENSION_TIME_DILATION[dimension]) || 1;
  return BASE_KEEPALIVE_TICKS * beta1;
}

/**
 * Calculate fast travel compression bonus.
 *
 * Base compression: β₁_from / β₁_to
 * Mastery bonus: cumulative from all mastered dimensions.
 *
 * Example: Dim 8→3 base = 21/3 = 7x
 * With full mastery through dim 8: 7x × (1 + 0.7) = 11.9x
 *
 * Teleport gets better with every dimension. Physics.
 */
export function calculateFastTravelCompression(
  fromDimension: DimensionIndex,
  toDimension: DimensionIndex,
  highestDimension: number
): number {
  const fromBeta = Math.abs(DIMENSION_TIME_DILATION[fromDimension]) || 1;
  const toBeta = Math.abs(DIMENSION_TIME_DILATION[toDimension]) || 1;
  const baseCompression = fromBeta / toBeta;

  // Accumulate fast travel bonus from mastered dimensions
  let travelBonus = 0;
  for (let d = 0; d <= Math.min(highestDimension, 9); d++) {
    const mastery = DIMENSIONAL_MASTERIES.get(d as GnosticDimensionIndex);
    if (mastery) travelBonus += mastery.fastTravelBonus;
  }

  return baseCompression * (1 + travelBonus);
}

// ── Optimism Exhaust Logging ────────────────────────────────────────

/**
 * Event types logged to Optimism via dashrelay-app bridge.
 * User doesn't care — but the chain does. Transparent web3.
 *
 * Every significant game action is logged as exhaust.
 * The data is immutable, verifiable, and public.
 * This is how proof-of-work drops are verified on-chain.
 */
export type OptimismExhaustEvent =
  | { type: 'observer_created'; did: string; seed: number; phyle: string; particleType: string }
  | { type: 'dimension_ascended'; did: string; dimension: number; totalFailures: number }
  | { type: 'item_dropped'; did: string; itemId: string; rarity: string; improbability: number; coordinateHash: string }
  | { type: 'item_traded'; fromDid: string; toDid: string; itemId: string; priceHex: number }
  | { type: 'fold_executed'; did: string; cycleCount: number; sliver: number }
  | { type: 'knot_defeated'; did: string; dimension: number; knotId: string }
  | { type: 'mastery_earned'; did: string; dimension: number; masteryName: string };

/**
 * Format an exhaust event for dashrelay-app bridge.
 * Returns the calldata for the Optimism transaction.
 *
 * The bridge is fire-and-forget. Game continues regardless.
 * But the record is permanent.
 */
export function formatExhaustForBridge(event: OptimismExhaustEvent): {
  readonly contractMethod: string;
  readonly args: readonly unknown[];
} {
  return {
    contractMethod: 'logGameExhaust',
    args: [event.type, JSON.stringify(event), Date.now()],
  };
}
